import './Expression.css';

const Expression = () => {
  const title = 'Expression';
  const arry = ['item1', 'item2', 'item3'];
  const hello = (arg) => `${arg} Function`;
  const JSX = <h3>Hello JSX</h3>
  return (
    <div className={title.toLowerCase()}>
      <h3>Hello {title}</h3>
      <h3>{arry}</h3>
      <h3>{hello('Hello')}</h3>
      <h3>{/* 何も表示されないコメント */}</h3>
      {<h3>Hello JSX</h3>}
    </div>
  );
};

export default Expression;
